defmodule BankServer.PartitionedSupervisor do
  @moduledoc """
  For higher throughput, partition accounts across multiple GenServers
  so that transactions on different account ranges can proceed in parallel,
  while transactions on the same account are still serialized.
  """

  use Supervisor

  @num_partitions 8

  def start_link(opts \\ []) do
    Supervisor.start_link(__MODULE__, opts, name: __MODULE__)
  end

  @impl true
  def init(_opts) do
    children =
      for i <- 0..(@num_partitions - 1) do
        %{
          id: {BankServer.Partition, i},
          start: {BankServer.Partition, :start_link, [i]}
        }
      end

    Supervisor.init(children, strategy: :one_for_one)
  end

  def deposit(account_id, amount) do
    partition = partition_for(account_id)
    GenServer.call(partition_name(partition), {:deposit, account_id, amount})
  end

  def withdraw(account_id, amount) do
    partition = partition_for(account_id)
    GenServer.call(partition_name(partition), {:withdraw, account_id, amount})
  end

  def transfer(from_account, to_account, amount) do
    from_partition = partition_for(from_account)
    to_partition = partition_for(to_account)

    if from_partition == to_partition do
      # Same partition — single GenServer handles it atomically
      GenServer.call(
        partition_name(from_partition),
        {:transfer, from_account, to_account, amount}
      )
    else
      # Cross-partition transfer: use a global lock / coordinator
      # to prevent deadlocks by always locking lower partition first
      {first, second} =
        if from_partition < to_partition,
          do: {from_partition, to_partition},
          else: {to_partition, from_partition}

      # Serialize cross-partition transfers through a dedicated coordinator
      GenServer.call(
        BankServer.TransferCoordinator,
        {:cross_partition_transfer, first, second, from_account, to_account, amount}
      )
    end
  end

  defp partition_for(account_id) do
    :erlang.phash2(account_id, @num_partitions)
  end

  defp partition_name(partition) do
    :"bank_partition_#{partition}"
  end
end

defmodule BankServer.Partition do
  use GenServer

