    table = :ets.new(table_name, [:set, :named_table, :private])
    {:ok, %{table: table, table_name: table_name}}
  end

  @impl true
  def handle_call({:create_account, account_id, initial_balance}, _from, state) do
    case :ets.lookup(state.table_name, account_id) do
      [] ->
        :ets.insert(state.table_name, {account_id, initial_balance})
        {:reply, {:ok, account_id}, state}

      _ ->
        {:reply, {:error, :account_already_exists}, state}
    end
  end

  @impl true
  def handle_call({:deposit, account_id, amount}, _from, state) do
    case :ets.lookup(state.table_name, account_id) do
      [] ->
        {:reply, {:error, :account_not_found}, state}

      [{^account_id, balance}] ->
        new_balance = balance + amount
        :ets.insert(state.table_name, {account_id, new_balance})
        {:reply, {:ok, new_balance}, state}
    end
  end

  @impl true
  def handle_call({:withdraw, account_id, amount}, _from, state) do
    case :ets.lookup(state.table_name, account_id) do
      [] ->
        {:reply, {:error, :account_not_found}, state}

      [{^account_id, balance}] when balance >= amount ->
        new_balance = balance - amount
        :ets.insert(state.table_name, {account_id, new_balance})
        {:reply, {:ok, new_balance}, state}

      [{^account_id, balance}] ->
        {:reply, {:error, {:insufficient_funds, balance}}, state}
    end
  end

  @impl true
  def handle_call({:transfer, from_account, to_account, amount}, _from, state) do
    with [{^from_account, from_bal}] <- :ets.lookup(state.table_name, from_account),
         [{^to_account, to_bal}] <- :ets.lookup(state.table_name, to_account),
         true <- from_bal >= amount do
      :ets.insert(state.table_name, {from_account, from_bal - amount})
      :ets.insert(state.table_name, {to_account, to_bal + amount})
      {:reply, {:ok, %{from: from_bal - amount, to: to_bal + amount}}, state}
    else
      [] -> {:reply, {:error, :account_not_found}, state}
      false ->
        [{^from_account, bal}] = :ets.lookup(state.table_name, from_account)
        {:reply, {:error, {:insufficient_funds, bal}}, state}
    end
  end

  @impl true
  def handle_call({:get_balance, account_id}, _from, state) do
    case :ets.lookup(state.table_name, account_id) do
      [] -> {:reply, {:error, :account_not_found}, state}
      [{^account_id, balance}] -> {:reply, {:ok, balance}, state}
    end
  end
end

defmodule BankServer.TransferCoordinator do
  @moduledoc """
  Coordinates cross-partition transfers to prevent race conditions
  and deadlocks. All cross-partition transfers are serialized through
  this single process, ensuring consistency.
  """
  use GenServer

  def start_link(_opts) do
    GenServer.start_link(__MODULE__, [], name: __MODULE__)
  end

  @impl true
  def init(_) do
    {:ok, %{}}
  end

  @impl true
  def handle_call(
        {:cross_partition_transfer, _first_part, _second_part, from_account, to_account, amount},
        _from,
        state
      ) do
    from_partition = :"bank_partition_#{:erlang.phash2(from_account, 8)}"
    to_partition = :"bank_partition_#{:erlang.phash2(to_account, 8)}"

    # Step 1: Withdraw from source (serialized in source partition)
    case GenServer.call(from_partition, {:withdraw, from_account, amount}) do
      {:ok, _new_from_balance} ->
        # Step 2: Deposit to destination (serialized in destination partition)
        case GenServer.call(to_partition, {:deposit, to_account, amount}) do
          {:ok, _new_to_balance} ->
            {:reply, {:ok, :transferred}, state}

          {:error, reason} ->
            # Compensate: re-deposit back to source
            GenServer.call(from_partition, {:deposit, from_account, amount})
            {:reply, {:error, reason}, state}
        end

      {:error, reason} ->
        {:reply, {:error, reason}, state}
    end
  end
end